#!/usr/bin/env bash
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
RCHD="${RCHD:-$PROJECT_ROOT/target/release/rchd}"
TEST_DIR=$(mktemp -d)
LOG_FILE="$TEST_DIR/e2e_status_api.log"
DAEMON_PID=""

export RCH_SOCKET="$TEST_DIR/rch.sock"
export RCH_LOG_LEVEL=debug

log() { echo "[$(date -Iseconds)] $*" | tee -a "$LOG_FILE"; }
pass() { log "PASS: $1"; }
fail() { log "FAIL: $1"; cleanup; exit 1; }

cleanup() {
    if [[ -n "$DAEMON_PID" ]]; then
        kill "$DAEMON_PID" 2>/dev/null || true
        wait "$DAEMON_PID" 2>/dev/null || true
    fi
    rm -rf "$TEST_DIR"
}
trap cleanup EXIT

log "=== /status API E2E Test ==="
log "Daemon binary: $RCHD"
log "Test dir: $TEST_DIR"
log "Socket: $RCH_SOCKET"

# Start daemon
start_daemon() {
    log "Starting daemon..."
    "$RCHD" --socket "$RCH_SOCKET" >> "$LOG_FILE" 2>&1 &
    DAEMON_PID=$!

    # Wait for socket
    for i in {1..30}; do
        if [[ -S "$RCH_SOCKET" ]]; then
            log "  Daemon started (PID: $DAEMON_PID)"
            return 0
        fi
        sleep 0.1
    done
    fail "Daemon socket not created"
}

# Helper to call /status API
call_status_api() {
    # Use socat or nc to send HTTP request to Unix socket
    if command -v socat &>/dev/null; then
        echo -e "GET /status HTTP/1.1\r\nHost: localhost\r\n\r\n" | \
            socat - UNIX-CONNECT:"$RCH_SOCKET" 2>/dev/null | \
            sed '1,/^\r$/d'
    else
        # Fallback: use Python
        python3 -c "
import socket
import json

sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
sock.connect('$RCH_SOCKET')
sock.send(b'GET /status HTTP/1.1\r\nHost: localhost\r\n\r\n')
response = sock.recv(65536).decode()
sock.close()

# Extract JSON body
body_start = response.find('\r\n\r\n') + 4
print(response[body_start:])
"
    fi
}

# Test 1: /status returns valid JSON
test_status_valid_json() {
    log "Test 1: /status returns valid JSON"

    RESPONSE=$(call_status_api)
    log "  Response (first 200 chars): $(echo "$RESPONSE" | head -c 200)"

    if echo "$RESPONSE" | python3 -c "import json,sys; json.load(sys.stdin)" 2>/dev/null; then
        pass "Valid JSON response"
    else
        fail "Invalid JSON response"
    fi
}

# Test 2: Response has required fields
test_status_required_fields() {
    log "Test 2: Response has required fields"

    RESPONSE=$(call_status_api)

    # Check top-level fields
    for field in daemon workers active_builds recent_builds issues; do
        if echo "$RESPONSE" | python3 -c "import json,sys; d=json.load(sys.stdin); assert '$field' in d" 2>/dev/null; then
            log "  Found: $field"
        else
            fail "Missing field: $field"
        fi
    done

    pass "All required fields present"
}

# Test 3: Daemon status is accurate
test_daemon_status() {
    log "Test 3: Daemon status accuracy"

    RESPONSE=$(call_status_api)

    # Check daemon PID matches
    RESPONSE_PID=$(echo "$RESPONSE" | python3 -c "import json,sys; print(json.load(sys.stdin)['daemon']['pid'])")

    if [[ "$RESPONSE_PID" == "$DAEMON_PID" ]]; then
        log "  PID matches: $RESPONSE_PID"
        pass "Daemon PID accurate"
    else
        fail "PID mismatch: expected $DAEMON_PID, got $RESPONSE_PID"
    fi
