test_uptime_increases() {
    log "Test 4: Uptime increases over time"

    UPTIME1=$(call_status_api | python3 -c "import json,sys; print(json.load(sys.stdin)['daemon']['uptime_secs'])")
    sleep 2
    UPTIME2=$(call_status_api | python3 -c "import json,sys; print(json.load(sys.stdin)['daemon']['uptime_secs'])")

    log "  Uptime 1: $UPTIME1, Uptime 2: $UPTIME2"

    if [[ "$UPTIME2" -gt "$UPTIME1" ]]; then
        pass "Uptime increases"
