use std::time::Instant;

pub struct CpuBenchmarkResult {
    pub score: f64,              // Normalized score (higher = faster)
    pub duration_ms: u64,
    pub iterations: u64,
    pub ops_per_second: f64,
}

/// Integer benchmark: Prime sieve (exercises integer ops, branching)
fn prime_sieve_benchmark(limit: usize) -> u64 {
    let mut sieve = vec![true; limit];
    sieve[0] = false;
    sieve[1] = false;

    for i in 2..((limit as f64).sqrt() as usize + 1) {
        if sieve[i] {
            for j in (i * i..limit).step_by(i) {
                sieve[j] = false;
            }
        }
    }

    sieve.iter().filter(|&&b| b).count() as u64
}

/// Floating-point benchmark: Matrix multiplication (exercises FP ops, cache)
fn matrix_multiply_benchmark(size: usize) -> f64 {
    let a: Vec<Vec<f64>> = (0..size).map(|i| 
        (0..size).map(|j| (i * j) as f64 / size as f64).collect()
    ).collect();
    let b = a.clone();
    let mut c = vec![vec![0.0f64; size]; size];

    for i in 0..size {
        for j in 0..size {
            for k in 0..size {
                c[i][j] += a[i][k] * b[k][j];
            }
        }
    }

    c[size/2][size/2]  // Return checksum value
}

/// Combined benchmark
pub fn run_cpu_benchmark() -> CpuBenchmarkResult {
    let start = Instant::now();

    // Run multiple iterations for stability
    let mut total_ops = 0u64;
    for _ in 0..10 {
        total_ops += prime_sieve_benchmark(100_000);
        let _ = matrix_multiply_benchmark(200);
    }

    let duration = start.elapsed();
    let ops_per_second = total_ops as f64 / duration.as_secs_f64();

    // Normalize to reference machine (M1 MacBook Pro baseline = 1000)
    let score = ops_per_second / 1_000_000.0 * 1000.0;

    CpuBenchmarkResult {
        score,
        duration_ms: duration.as_millis() as u64,
        iterations: 10,
        ops_per_second,
    }
}
