### Data Sources (Linux)
```rust
// Read from /proc/meminfo
// Key fields we need:
// MemTotal:       16384000 kB
// MemFree:         1234000 kB
// MemAvailable:   10240000 kB  <- Best indicator of usable memory
// Buffers:          512000 kB
// Cached:          2048000 kB
// SwapTotal:       8192000 kB
// SwapFree:        8000000 kB
// Dirty:             12345 kB
// Writeback:             0 kB

pub struct MemoryInfo {
    pub total_kb: u64,
    pub free_kb: u64,
    pub available_kb: u64,  // MemAvailable (kernel estimate of usable)
    pub buffers_kb: u64,
    pub cached_kb: u64,
    pub swap_total_kb: u64,
    pub swap_free_kb: u64,
    pub dirty_kb: u64,
    pub writeback_kb: u64,
}

impl MemoryInfo {
    pub fn read_from_proc() -> Result<Self> {
        let content = std::fs::read_to_string("/proc/meminfo")?;
        Self::parse(&content)
    }

    pub fn parse(content: &str) -> Result<Self> {
        // Parse key:value pairs
        let mut map = HashMap::new();
        for line in content.lines() {
            if let Some((key, value)) = line.split_once(':') {
                let kb = value.trim().trim_end_matches(" kB")
                    .parse::<u64>().ok();
                if let Some(kb) = kb {
                    map.insert(key.to_string(), kb);
                }
            }
        }
        // Extract fields from map
    }
}
```

### Derived Metrics
```rust
impl MemoryInfo {
    /// Percentage of memory in use (0-100)
    pub fn used_percent(&self) -> f64 {
        let used = self.total_kb - self.available_kb;
        (used as f64 / self.total_kb as f64) * 100.0
    }

    /// Memory pressure score (0-100, higher = more pressure)
    /// Accounts for swap usage and dirty pages
    pub fn pressure_score(&self) -> f64 {
        let base = self.used_percent();

        // Add pressure for swap usage
        let swap_used = self.swap_total_kb - self.swap_free_kb;
        let swap_pressure = if self.swap_total_kb > 0 {
            (swap_used as f64 / self.swap_total_kb as f64) * 20.0
        } else {
            0.0
        };

        // Add pressure for dirty pages (pending writes)
        let dirty_pressure = (self.dirty_kb as f64 / 1_000_000.0) * 5.0;

        (base + swap_pressure + dirty_pressure).min(100.0)
    }

    /// Estimated available memory for new allocations
    pub fn available_gb(&self) -> f64 {
        self.available_kb as f64 / 1_048_576.0
    }
}
